// v2.0：完整重新設計 — 任意 N 個輸入都穩健

const GEMINI_API_KEY = '__GEMINI_API_KEY__';
const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const items = $input.all();
const allReadItems = $('Read 所有檔案').all();

function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }

function safePathSegment(s) {
  return String(s || '').replace(/[\\/:*?"<>|\x00-\x1f]/g, '_').substring(0, 100);
}

function cleanLeadingDigits(name) {
  const noExt = name.replace(/\.[^.]+$/, '');
  const cleaned = noExt.replace(/^[\s\-_.()【】]+/, '').trim();
  return cleaned || noExt;
}

function filterPrintable(text) {
  if (!text || typeof text !== 'string') return '';
  const printableMatches = text.match(/[\u4e00-\u9fff\u3000-\u303f\uff00-\uffefa-zA-Z0-9\s.,!?;:()\[\]{}\-+="'\/_*&%$#@~|<>]/g);
  const ratio = printableMatches ? printableMatches.length / text.length : 0;
  return ratio > 0.7 ? text.substring(0, 800) : '';
}

function classifyByFilename(name, ext) {
  const n = name.toLowerCase();
  const e = (ext || '').toLowerCase();
  if (['jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'svg', 'bmp', 'tiff'].includes(e)) {
    return { category: 'images', semanticType: '圖片' };
  }
  if (['ppt', 'pptx', 'key'].includes(e) || /簡報|投影片|提案|pitch|proposal|kickoff|deck/i.test(n)) {
    return { category: 'presentations', semanticType: '簡報' };
  }
  if (/合約|協議|nda|授權書|同意書|條款/i.test(n)) return { category: 'contracts', semanticType: '合約' };
  if (/發票|收據|報價|估價|帳單|對帳|訂單|invoice|quote/i.test(n)) return { category: 'invoices', semanticType: '報價' };
  if (/會議|紀錄|逐字稿|memo|minutes|meeting/i.test(n)) return { category: 'docs', semanticType: '紀錄' };
  if (/提示詞|prompt|教材|講義|手冊|教學|課程/i.test(n)) return { category: 'docs', semanticType: '教材' };
  if (/規格|spec|brief|需求/i.test(n)) return { category: 'docs', semanticType: '規格' };
  if (/報告|report|分析|analysis/i.test(n)) return { category: 'docs', semanticType: '報告' };
  return null;
}

function classifyByContent(text) {
  if (!text || text.length < 30) return null;
  const t = text.substring(0, 1500).toLowerCase();
  if (/合約|協議|nda|授權書|同意書|條款|甲方.*乙方|nondisclosure/i.test(t)) return { category: 'contracts', semanticType: '合約' };
  if (/發票|收據|報價|估價|帳單|對帳|金額.*nt\$|invoice|quote|稅金/i.test(t)) return { category: 'invoices', semanticType: '報價' };
  if (/簡報|投影片|提案/i.test(t)) return { category: 'presentations', semanticType: '簡報' };
  if (/會議|紀錄|memo|minutes|出席|議題|待辦/i.test(t)) return { category: 'docs', semanticType: '紀錄' };
  if (/提示詞|prompt engineering|教材|講義|教學|課程/i.test(t)) return { category: 'docs', semanticType: '教材' };
  return null;
}

function smartFallback(name, ext, text) {
  return classifyByFilename(name, ext) || classifyByContent(text) || { category: 'docs', semanticType: '文件' };
}

const CATEGORIES = ['contracts','invoices','presentations','docs','images','others'];
const imgExts = ['jpg', 'jpeg', 'png', 'gif', 'webp', 'heic', 'svg', 'bmp', 'tiff'];

// === 預檢 ===
const N = allReadItems.length;
if (N === 0) {
  const msg = 'client-inbox 是空的，沒有檔案可整理。';
  return [{
    json: {
      originalName: '(empty)',
      category: 'docs',
      newName: 'no-files-' + today + '.md',
      newPath: '/files/shared/client-organized/docs/no-files-' + today + '.md',
      indexLine: '_(client-inbox 是空的)_',
      _batchInfo: { inputCount: 0, outputCount: 0, message: msg }
    },
    binary: {
      data: {
        data: Buffer.from('\ufeff' + ('# 整理結果\n\n' + msg), 'utf-8').toString('base64'),
        mimeType: 'text/markdown',
        fileName: 'no-files.md'
      }
    }
  }];
}

// === 動態調整 chunk size 與 throttle ===
const CHUNK_SIZE = N >= 30 ? 8 : 5;
const INTER_CHUNK_DELAY = 7000;
const RETRY_429_WAIT = 60000;

// === 建 fileName → 內文查表（從 post-Extract items）===
const textMap = new Map();
for (const it of items) {
  const fn = it.binary?.data?.fileName;
  if (!fn) continue;
  const t = it.json?.text ?? it.json?.data;
  if (t != null) textMap.set(fn, t);
}

// === Phase 1：迭代 Read 原始 items（保證 100% 不漏）+ 圖檔直送 ===
const processed = [];
for (let i = 0; i < N; i++) {
  const readItem = allReadItems[i];
  if (!readItem?.binary?.data) continue;

  const originalName = readItem.json.fileName || ('unknown-' + (i + 1));
  const fileExt = (readItem.json.fileExtension || '').toLowerCase();
  const fileSize = readItem.binary.data.fileSize || 0;
  const rawText = textMap.get(originalName) ?? '';
  const usableText = filterPrintable(rawText);

  const base = {
    idx: i, originalName, fileExt, fileSize, usableText, binary: readItem.binary,
    category: null, newName: null, aiUsed: false, aiError: null, ruleHit: null
  };

  if (imgExts.includes(fileExt)) {
    base.category = 'images';
    base.newName = today + '_圖片_' + cleanLeadingDigits(originalName);
    base.ruleHit = 'image-by-ext';
  }

  processed.push(base);
}

// === Phase 2：批次 AI 呼叫 ===
const needsAI = processed.filter(p => !p.category);
const chunks = [];
for (let i = 0; i < needsAI.length; i += CHUNK_SIZE) chunks.push(needsAI.slice(i, i + CHUNK_SIZE));

const t0 = Date.now();
const batchInfo = {
  inputCount: N,
  extractedCount: textMap.size,
  imageDirectCount: processed.filter(p => p.category === 'images').length,
  needsAICount: needsAI.length,
  outputCount: 0,
  dedupCount: 0,
  chunks: chunks.length,
  chunkSize: CHUNK_SIZE,
  aiCalls: 0,
  totalMs: 0,
  batchErrors: [],
  aiSucceeded: 0,
  ruleFallback: 0,
  warnings: []
};

if (N > 50) batchInfo.warnings.push('輸入 ' + N + ' 檔超過 50，跑時較長 + 可能撞 Gemini RPM 限速。建議分批');
if (N > 200) batchInfo.warnings.push('輸入 ' + N + ' 檔超過 200，可能撞 n8n 300s task timeout');

async function callGeminiBatch(chunk) {
  const filesPart = chunk.map((f, idx) => {
    const docxHint = ['docx', 'xlsx', 'pptx'].includes(f.fileExt) ? '\n注意：Office 檔（' + f.fileExt + '）無內文，請用檔名分類' : '';
    const contentPart = f.usableText ? '\n內容摘要：' + f.usableText : '\n（無法擷取內文，憑檔名分類）';
    return '<檔案 ' + (idx + 1) + '>\n檔名：' + f.originalName + '\n副檔名：' + f.fileExt + docxHint + contentPart + '\n</檔案 ' + (idx + 1) + '>';
  }).join('\n\n');

  const prompt = '你是檔案歸檔助手。對下面 ' + chunk.length + ' 份檔案分類成 6 類之一，並取語意化檔名。\n\n' +
    '**類別**（看不出明確類型優先 docs；only fallback 到 others 在真的什麼都不像）：\n' +
    '- contracts：合約 / NDA / 條款 / 授權書\n' +
    '- invoices：發票 / 收據 / 報價單 / 估價單 / 帳單\n' +
    '- presentations：簡報 / 投影片 / 提案 / pitch deck\n' +
    '- docs：所有文字內容文件（手冊 / 筆記 / 會議記錄 / 教材 / 講義 / 報告 / 任何 .txt/.md/.docx）\n' +
    '- images：圖片 / 截圖\n' +
    '- others：真的什麼都不像才選\n\n' +
    '**重要：保留檔名中的數字編號 + 區分標記**\n' +
    '檔名有 01/02/03、v1/v2、Q3、_LLM 等區分 token 時必須保留，避免命名衝突。\n\n' +
    '**範例**：\n' +
    '- 合約_NDA_客戶A.pdf → {"category":"contracts","newName":"' + today + '_合約_客戶A NDA"}\n' +
    '- Q3-報價單.pdf → {"category":"invoices","newName":"' + today + '_報價_Q3"}\n' +
    '- 客戶提案v3.pptx → {"category":"presentations","newName":"' + today + '_簡報_客戶提案v3"}\n' +
    '- 中小企業AI實務01.pptx → {"category":"presentations","newName":"' + today + '_簡報_中小企業AI實務01"}\n' +
    '- 中小企業AI實務02.pptx → {"category":"presentations","newName":"' + today + '_簡報_中小企業AI實務02"}\n' +
    '- 通用觀念_LLM.pptx → {"category":"presentations","newName":"' + today + '_簡報_通用觀念LLM"}\n' +
    '- 01提示詞基礎.docx → {"category":"docs","newName":"' + today + '_教材_提示詞基礎01"}\n' +
    '- 虛擬會議逐字稿.docx → {"category":"docs","newName":"' + today + '_紀錄_虛擬會議逐字稿"}\n\n' +
    '**輸出規則**：嚴格只回 JSON array，array 順序與輸入順序一致，array 長度必須 = ' + chunk.length + '。\n' +
    '不要 markdown 包裹。\n\n' +
    '格式：[{"category":"xxx","newName":"' + today + '_類型_關鍵字"}, ...]\n\n' +
    filesPart;

  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent',
    headers: { 'Content-Type': 'application/json', 'x-goog-api-key': GEMINI_API_KEY },
    body: {
      contents: [{ role: 'user', parts: [{ text: prompt }] }],
      generationConfig: { temperature: 0.2, maxOutputTokens: 2000, thinkingConfig: { thinkingBudget: 0 } }
    },
    json: true,
    timeout: 60000
  });
  const aiResp = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = aiResp.replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (!m) throw new Error('no JSON array in AI response: ' + cleaned.substring(0, 200));
  const arr = JSON.parse(m[0]);
  if (!Array.isArray(arr)) throw new Error('AI response is not an array');
  return arr;
}

for (let cIdx = 0; cIdx < chunks.length; cIdx++) {
  if (cIdx > 0) await sleep(INTER_CHUNK_DELAY);

  const chunk = chunks[cIdx];
  let arr = null;
  let lastError = null;

  for (let attempt = 0; attempt < 2; attempt++) {
    batchInfo.aiCalls++;
    try {
      arr = await callGeminiBatch(chunk);
      lastError = null;
      break;
    } catch (err) {
      lastError = err.message || String(err);
      if (lastError.includes('429') && attempt === 0) {
        await sleep(RETRY_429_WAIT);
        continue;
      }
      break;
    }
  }

  if (lastError) batchInfo.batchErrors.push('chunk ' + cIdx + ': ' + lastError.substring(0, 100));

  // Per-file fallback：每檔獨立判，AI 失敗也單獨 rule 救
  for (let j = 0; j < chunk.length; j++) {
    const f = chunk[j];
    const r = arr && arr[j] ? arr[j] : null;
    if (r && CATEGORIES.includes(r.category)) {
      f.category = r.category;
      f.newName = r.newName || (today + '_' + cleanLeadingDigits(f.originalName));
      f.aiUsed = true;
      batchInfo.aiSucceeded++;
    } else {
      f.aiError = lastError || 'AI returned invalid for index ' + j;
      const rule = smartFallback(f.originalName, f.fileExt, f.usableText);
      f.category = rule.category;
      f.newName = today + '_' + rule.semanticType + '_' + cleanLeadingDigits(f.originalName);
      f.ruleHit = 'rule:' + rule.semanticType;
      f.aiUsed = false;
      batchInfo.ruleFallback++;
    }
  }
}

batchInfo.totalMs = Date.now() - t0;

// === Phase 3：dedup + format final results ===
const seenNewNames = new Map();
const results = [];

for (let i = 0; i < processed.length; i++) {
  const f = processed[i];
  if (!f.category) f.category = 'docs';
  if (!f.newName) f.newName = today + '_文件_' + cleanLeadingDigits(f.originalName);

  let bareName = safePathSegment(f.newName);
  if (!bareName.match(/^\d{8}_/)) bareName = today + '_' + bareName;
  bareName = bareName.replace(/\.[a-z0-9]{2,5}$/i, '');

  const key = f.category + '/' + bareName;
  let finalName = bareName;
  if (seenNewNames.has(key)) {
    const count = seenNewNames.get(key) + 1;
    seenNewNames.set(key, count);
    finalName = bareName + '_' + count;
    batchInfo.dedupCount++;
  } else {
    seenNewNames.set(key, 1);
  }

  if (f.fileExt) finalName = finalName + '.' + f.fileExt;

  const out = {
    json: {
      originalName: f.originalName,
      category: f.category,
      newName: finalName,
      newPath: '/files/shared/client-organized/' + f.category + '/' + finalName,
      indexLine: '- **' + f.category + '** · ' + finalName + ' ← ' + f.originalName + (f.aiUsed ? '' : ' _(rule)_'),
      aiUsed: f.aiUsed,
      aiError: f.aiError,
      ruleHit: f.ruleHit,
      fileSize: f.fileSize
    },
    binary: f.binary
  };
  results.push(out);
}

batchInfo.outputCount = results.length;
if (results.length > 0) results[0].json._batchInfo = batchInfo;

return results;

const data = $input.first().json;
const lines = data.indexLine || [];
const cats = data.category || [];
const total = lines.length;
const counts = {};
for (const c of cats) counts[c] = (counts[c] || 0) + 1;

const today = new Date().toISOString().slice(0, 10);
const markdown = '# 客戶資料夾整理交接包 · ' + today + '\n\n' +
  '總共整理 ' + total + ' 份檔案。\n\n' +
  '## 分類統計\n' + Object.entries(counts).map(([k, v]) => '- ' + k + '：' + v + ' 份').join('\n') + '\n\n' +
  '## 檔案清單\n' + lines.join('\n') + '\n\n' +
  '---\n_自動產生於 ' + new Date().toLocaleString('zh-TW') + '_';

const tgMsg = '✅ 客戶資料夾整理完成\n\n' +
  '總計：' + total + ' 份\n' +
  Object.entries(counts).map(([k, v]) => k + '：' + v).join(' / ') + '\n\n' +
  '完整清單：shared/client-organized/_index.md';

return [{
  json: { tgMsg, indexPath: '/files/shared/client-organized/_index.md', total },
  binary: {
    data: {
      data: Buffer.from('\ufeff' + (markdown), 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: '_index.md'
    }
  }
}];
